 1	import React, { FC, ReactNode } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 5	import {
 6	  Button,
 7	  ButtonVariant,
 8	  ClipboardCopy,
 9	  ClipboardCopyVariant,
10	  Popover,
11	  PopoverPosition,
12	} from '@patternfly/react-core';
13	import { IpAddresses } from '@virtualmachines/details/tabs/overview/components/VirtualMachinesOverviewTabNetworkInterfaces/utils/types';
14	
15	type FirstItemListPopoverProps = {
16	  className?: string;
17	  headerContent?: ReactNode | string;
18	  includeCopyFirstItem?: boolean;
19	  items: IpAddresses;
20	};
21	
22	const FirstItemListPopover: FC<FirstItemListPopoverProps> = ({
23	  className,
24	  headerContent,
25	  includeCopyFirstItem,
26	  items,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  return (
30	    <div className={className}>
31	      <div>
32	        {items?.[0] && includeCopyFirstItem ? (
33	          <ClipboardCopy
34	            clickTip={t('Copied')}
35	            hoverTip={t('Copy to clipboard')}
36	            isCode
37	            variant={ClipboardCopyVariant.inlineCompact}
38	          >
39	            {items?.[0]?.ip}
40	          </ClipboardCopy>
41	        ) : (
42	          items?.[0]?.ip || NO_DATA_DASH
43	        )}
44	      </div>
45	      {items?.length > 1 && (
46	        <Popover
47	          bodyContent={items.map(({ interfaceName, ip }) => (
48	            <div key={ip}>
49	              {interfaceName}: {ip}
50	            </div>
51	          ))}
52	          hasAutoWidth
53	          headerContent={headerContent}
54	          position={PopoverPosition.top}
55	        >
56	          <Button variant={ButtonVariant.link}>{`+${items.length - 1} more`}</Button>
57	        </Popover>
58	      )}
59	    </div>
60	  );
61	};
62	
63	FirstItemListPopover.defaultProps = {
64	  className: '',
65	  headerContent: '',
66	};
67	
68	export default FirstItemListPopover;

